import Tarjeta from "../tarjetas-simple-doble/tarjeta/tarjeta";
import "./index-first.css";

function IndexFirst(){



    return(
        <div className="container">
            <img src="Burguer-cuadrada.png" alt="Burguer"/>
            <div className="promos">
                <Tarjeta ruta="/repartidor.png" titulo="¡Llegamos hasta tu casa 24Hs!" descripcion="Disfruta nuestras hamburguesas a domicilio, ahora con entrega rápida y segura."/>
                <Tarjeta ruta="/parrilla.jpg"/>
            </div>
        </div>
    );
};

export default IndexFirst;
